            throw new IOException("Configuration file not found: " + configPath);
        }
        if (!configFile.canRead()) {
            throw new IOException("Cannot read configuration file: " + configPath);
        }

        // Step 1: Validate XML is well-formed using SchemaFactory
        validateXmlWellFormed(configFile);

        // Step 2: Parse the validated XML into Document object
        return parseXmlDocument(configFile);
    }

    /**
     * Validates that the XML file is well-formed.
     * Uses XML Schema 1.0 to validate basic XML structure.
     *
     * @param xmlFile the XML file to validate
     * @throws SAXException if validation fails
     * @throws IOException if file reading fails
     */
    private void validateXmlWellFormed(File xmlFile) throws SAXException, IOException {
        // Create SchemaFactory for XML Schema 1.0
        SchemaFactory schemaFactory = SchemaFactory.newInstance(XMLConstants.W3C_XML_SCHEMA_NS_URI);

        // Configure SchemaFactory to be secure against XXE attacks
        schemaFactory.setProperty(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        schemaFactory.setProperty(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

        // Create an empty schema - this will only validate well-formedness
        Schema schema = schemaFactory.newSchema();

        // Create Validator
        Validator validator = schema.newValidator();

        // Configure Validator to be secure against XXE attacks
        validator.setProperty(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        validator.setProperty(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

        // Create Source from file
        Source source = new StreamSource(xmlFile);

        // Perform validation
        validator.validate(source);
    }

    /**
     * Parses the validated XML file into a Document object.
     *
     * @param xmlFile the validated XML file
     * @return the parsed Document object
     * @throws ParserConfigurationException if DocumentBuilder cannot be configured
     * @throws SAXException if parsing fails
     * @throws IOException if file reading fails
     */
    private Document parseXmlDocument(File xmlFile) 
            throws ParserConfigurationException, SAXException, IOException {

        // Create DocumentBuilderFactory
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

        // Secure the DocumentBuilderFactory against XXE attacks
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        // Create DocumentBuilder
        DocumentBuilder builder = factory.newDocumentBuilder();

        // Parse the XML file
        return builder.parse(xmlFile);
    }
}
